23	static std::unique_ptr<RouterLookahead> make_router_lookahead_object(const t_det_routing_arch& det_routing_arch,
24	                                                                     e_router_lookahead router_lookahead_type,
25	                                                                     bool is_flat,
26	                                                                     int route_verbosity,
27	                                                                     bool device_model_warnings,
28	                                                                     float interposer_base_cut_multiplier) {
29	    if (router_lookahead_type == e_router_lookahead::CLASSIC) {
30	        return std::make_unique<ClassicLookahead>();
31	    } else if (router_lookahead_type == e_router_lookahead::MAP) {
32	        return std::make_unique<MapLookahead>(det_routing_arch, is_flat, route_verbosity, device_model_warnings, interposer_base_cut_multiplier);
33	    } else if (router_lookahead_type == e_router_lookahead::COMPRESSED_MAP) {
34	        return std::make_unique<CompressedMapLookahead>(det_routing_arch, is_flat, route_verbosity, device_model_warnings);
35	    } else if (router_lookahead_type == e_router_lookahead::EXTENDED_MAP) {
36	        return std::make_unique<ExtendedMapLookahead>(is_flat, route_verbosity, device_model_warnings);
37	    } else if (router_lookahead_type == e_router_lookahead::SIMPLE) {
38	        return std::make_unique<SimpleLookahead>();
39	    } else if (router_lookahead_type == e_router_lookahead::NO_OP) {
40	        return std::make_unique<NoOpLookahead>();
41	    }
42	
43	    VPR_FATAL_ERROR(VPR_ERROR_ROUTE, "Unrecognized router lookahead type");
44	    return nullptr;
45	}
