56	    std::unique_ptr<RouterLookahead> router_lookahead = make_router_lookahead_object(det_routing_arch,
57	                                                                                     router_lookahead_type,
58	                                                                                     is_flat,
59	                                                                                     route_verbosity,
60	                                                                                     device_model_warnings,
61	                                                                                     router_lookahead_interposer_base_cut_multiplier);
62	
63	    if (read_lookahead.empty()) {
64	        router_lookahead->compute(segment_inf);
65	    } else {
66	        router_lookahead->read(read_lookahead);
67	    }
68	
69	    if (!write_lookahead.empty()) {
70	        router_lookahead->write(write_lookahead);
71	    }
72	
73	    return router_lookahead;
