82	std::pair<float, float> ClassicLookahead::get_expected_delay_and_cong(RRNodeId node, RRNodeId target_node, const t_conn_cost_params& params, float R_upstream) const {
83	    const DeviceContext& device_ctx = g_vpr_ctx.device();
84	    const auto& rr_graph = device_ctx.rr_graph;
85	
86	    e_rr_type rr_type = rr_graph.node_type(node);
87	
88	    if (rr_type == e_rr_type::CHANX || rr_type == e_rr_type::CHANY) {
89	        auto [num_segs_same_dir, num_segs_ortho_dir] = get_expected_segs_to_target(node, target_node);
90	
91	        RRIndexedDataId cost_index = rr_graph.node_cost_index(node);
92	        int ortho_cost_index = device_ctx.rr_indexed_data[cost_index].ortho_cost_index;
93	
94	        const auto& same_data = device_ctx.rr_indexed_data[cost_index];
95	        const auto& ortho_data = device_ctx.rr_indexed_data[RRIndexedDataId(ortho_cost_index)];
96	        const auto& ipin_data = device_ctx.rr_indexed_data[RRIndexedDataId(IPIN_COST_INDEX)];
97	        const auto& sink_data = device_ctx.rr_indexed_data[RRIndexedDataId(SINK_COST_INDEX)];
98	
99	        float cong_cost = num_segs_same_dir * same_data.base_cost
100	                          + num_segs_ortho_dir * ortho_data.base_cost
101	                          + ipin_data.base_cost
102	                          + sink_data.base_cost;
103	
104	        float Tdel = num_segs_same_dir * same_data.T_linear
105	                     + num_segs_ortho_dir * ortho_data.T_linear
106	                     + num_segs_same_dir * num_segs_same_dir * same_data.T_quadratic
107	                     + num_segs_ortho_dir * num_segs_ortho_dir * ortho_data.T_quadratic
108	                     + R_upstream * (num_segs_same_dir * same_data.C_load + num_segs_ortho_dir * ortho_data.C_load)
109	                     + ipin_data.T_linear;
110	
111	        return std::make_pair(params.criticality * Tdel, (1 - params.criticality) * cong_cost);
112	    } else if (rr_type == e_rr_type::IPIN) { /* Change if you're allowing route-throughs */
113	        return std::make_pair(0., device_ctx.rr_indexed_data[RRIndexedDataId(SINK_COST_INDEX)].base_cost);
114	
115	    } else { /* Change this if you want to investigate route-throughs */
116	        return std::make_pair(0., 0.);
117	    }
118	}
