26	namespace util {
27	
28	class Cost_Entry;
29	
30	class Expansion_Cost_Entry;
31	/* used during Dijkstra expansion to store delay/congestion info lists for each relative coordinate for a given segment and channel type.
32	 * the list at each coordinate is later boiled down to a single representative cost entry to be stored in the final cost map */
33	typedef vtr::NdMatrix<Expansion_Cost_Entry, 3> t_routing_cost_map; //[0..num_layers][0..device_ctx.grid.width()-1][0..device_ctx.grid.height()-1]
34	
35	typedef Cost_Entry (*WireCostCallBackFunction)(e_rr_type, int, int, int, int, int);
36	
37	/* a class that represents an entry in the Dijkstra expansion priority queue */
38	class PQ_Entry {
39	  public:
40	    RRNodeId rr_node; //index in device_ctx.rr_nodes that this entry represents
41	    float cost;       //the cost of the path to get to this node
42	
43	    /* store backward delay, R and congestion info */
44	    float delay;
45	    float R_upstream;
46	    float congestion_upstream;
47	
48	    PQ_Entry(RRNodeId set_rr_node, int /*switch_ind*/, float parent_delay, float parent_R_upstream, float parent_congestion_upstream, bool starting_node);
49	
50	    bool operator<(const PQ_Entry& obj) const {
51	        /* inserted into max priority queue so want queue entries with a lower cost to be greater */
52	        return (this->cost > obj.cost);
53	    }
54	};
55	
56	struct t_dijkstra_data {
57	    /* a list of boolean flags (one for each rr node) to figure out if a certain node has already been expanded */
58	    vtr::vector<RRNodeId, bool> node_expanded;
59	    /* for each node keep a list of the cost with which that node has been visited (used to determine whether to push
60	     * a candidate node onto the expansion queue */
61	    vtr::vector<RRNodeId, float> node_visited_costs;
62	    /* a priority queue for expansion */
63	    std::priority_queue<PQ_Entry> pq;
64	};
