179	// Keys in the RoutingCosts map
180	struct RoutingCostKey {
181	    // segment type index
182	    int seg_index;
183	
184	    // offset of the destination connection box from the starting segment
185	    vtr::Point<int> delta;
186	
187	    RoutingCostKey()
188	        : seg_index(-1)
189	        , delta(0, 0) {}
190	    RoutingCostKey(int seg_index_arg, vtr::Point<int> delta_arg)
191	        : seg_index(seg_index_arg)
192	        , delta(delta_arg) {}
193	
194	    bool operator==(const RoutingCostKey& other) const {
195	        return seg_index == other.seg_index && delta == other.delta;
196	    }
197	};
198	
199	// hash implementation for RoutingCostKey
200	struct HashRoutingCostKey {
201	    std::size_t operator()(RoutingCostKey const& key) const noexcept {
202	        std::size_t hash = std::hash<int>{}(key.seg_index);
203	        vtr::hash_combine(hash, key.delta.x());
204	        vtr::hash_combine(hash, key.delta.y());
205	        return hash;
206	    }
207	};
208	
209	// Map used to store intermediate routing costs
210	typedef std::unordered_map<RoutingCostKey, float, HashRoutingCostKey> RoutingCosts;
211	
