214	  public:
215	    RRNodeId rr_node; //index in device_ctx.rr_nodes that this entry represents
216	    float delay_cost; //the cost of the path to get to this node
217	
218	    PQ_Entry_Delay(RRNodeId set_rr_node, int /*switch_ind*/, const PQ_Entry_Delay* parent);
219	
