230	    }
231	};
232	
233	// A version of PQ_Entry that only calculates and stores the base cost.
234	class PQ_Entry_Base_Cost {
235	  public:
236	    RRNodeId rr_node; //index in device_ctx.rr_nodes that this entry represents
237	    float base_cost;
238	
239	    PQ_Entry_Base_Cost(RRNodeId set_rr_node, int /*switch_ind*/, const PQ_Entry_Base_Cost* parent);
240	
