280	//[0..device_ctx.physical_tile_types.size()-1][0..max_ptc-1][wire_seg_index]
281	// ^                                           ^             ^
282	// |                                           |             |
283	// physical block type index                   |             Reachable wire info
284	//                                             |
285	//                                             SOURCE/OPIN ptc
286	//
287	// This data structure stores a set of delay and congestion values for each wire that can be reached from a given
288	// SOURCE/OPIN of a given tile type.
289	//
290	// When querying this data structure, the minimum cost is computed for each delay/congestion pair, and returned
291	// as the lookahead expected cost. [opin/src layer_num][tile_index][opin/src ptc_number][to_layer_num] -> pair<seg_index, t_reachable_wire_inf>
292	typedef std::vector<std::vector<std::vector<std::vector<std::map<int, t_reachable_wire_inf>>>>> t_src_opin_delays;
293	
