301	//                                             |
302	//                                             SINK ptc
303	//
304	// This data structure stores the minimum delay to reach a specific SINK from the last connection between the wire (CHANX/CHANY)
305	// and the tile's IPIN. If there are many connections to the same IPIN, the one with the minimum delay is selected.
306	typedef std::vector<std::vector<std::vector<t_reachable_wire_inf>>> t_chan_ipins_delays;
307	
308	typedef Cost_Entry (*WireCostFunc)(e_rr_type, int, int, int, int, int);
309	
310	/**
311	 * @brief For each tile, iterate over its OPINs and store which segment types are accessible from each OPIN
312	 */
313	t_src_opin_delays compute_router_src_opin_lookahead(bool is_flat,
314	                                                    int route_verbosity,
315	                                                    bool device_model_warnings);
316	
317	t_chan_ipins_delays compute_router_chan_ipin_lookahead(int route_verbosity,
318	                                                       bool device_model_warnings);
319	
320	t_ipin_primitive_sink_delays compute_intra_tile_dijkstra(const RRGraphView& rr_graph,
321	                                                         t_physical_tile_type_ptr physical_tile,
322	                                                         const t_physical_tile_loc& tile_loc);
323	
324	/* returns index of a node from which to start routing */
325	RRNodeId get_chanxy_start_node(int layer, int start_x, int start_y, int target_x, int target_y, e_rr_type rr_type, int seg_index, int track_offset);
326	RRNodeId get_chanz_start_node(int start_x, int start_y, int seg_index, int track_offset, Direction dir);
327	
328	/**
329	 * @brief Computes the absolute delta_x and delta_y offset
330	 * required to reach to_node from from_node
331	 * @param from_node The starting node
332	 * @param to_node The destination node
333	 * @return (delta_x, delta_y) offset required to reach to
334	 * to_node from from_node.
335	 */
336	std::pair<int, int> get_xy_deltas(RRNodeId from_node, RRNodeId to_node);
337	
338	/**
339	 * @brief Computes the adjusted position of an RR graph node.
340	 * This function does not modify the position of the given node.
341	 * It only returns the computed adjusted position.
342	 * Adjusted position is:
343	 *  - CHANX/CHANY nodes: Position of the driver for directional wires and wire center for bidirectional wires
344	 *  - CHANZ nodes: (xlow, ylow) of the node, which would be the same as (xhigh, yhigh)
345	 *  - OPIN/IPIN nodes: Position of the channel it can reach based on which side of the block it is at.
346	 *  - SOURCE/SINK nodes: Centroid of the tile
347	 * @param rr The ID of the node whose adjusted position is desired.
348	 * @return The adjusted position (x, y).
349	 */
350	std::pair<int, int> get_adjusted_rr_position(const RRNodeId rr);
351	
352	t_routing_cost_map get_routing_cost_map(int longest_seg_length,
353	                                        unsigned from_layer_num,
354	                                        const e_rr_type chan_type,
355	                                        const t_segment_inf& segment_inf,
356	                                        const std::unordered_map<int, std::unordered_set<int>>& sample_locs,
357	                                        bool sample_all_locs,
358	                                        int route_verbosity,
359	                                        bool device_model_warnings);
360	
361	/**
362	 * @brief Iterate over all of the wire segments accessible from the SOURCE/OPIN (stored in src_opin_delay_map) and return the minimum cost (congestion and delay) across them to the sink
363	 * @param src_opin_delay_map
364	 * @param delta_x
365	 * @param delta_y
366	 * @param to_layer_num
367	 * @param wire_cost_func call back function that would return a cost to get to a given location from the given segment
368	 * @return (delay, congestion)
369	 */
370	std::pair<float, float> get_cost_from_src_opin(const std::map<int, util::t_reachable_wire_inf>& src_opin_delay_map,
371	                                               int delta_x,
372	                                               int delta_y,
373	                                               int to_layer_num,
374	                                               WireCostFunc wire_cost_func);
375	
376	void dump_readable_router_lookahead_map(const std::string& file_name,
377	                                        const std::vector<int>& dim_sizes,
378	                                        WireCostCallBackFunction wire_cost_func);
379	
380	/// @brief Converts a routing channel type (CHANX/CHANY/CHANZ) to an index
381	/// to access the channel type dimension of the router lookahead table.
382	inline int chan_type_to_index(e_rr_type chan_type) {
383	    int chan_index;
384	    switch (chan_type) {
385	        case e_rr_type::CHANX:
386	            chan_index = 0;
387	            break;
388	        case e_rr_type::CHANY:
389	            chan_index = 1;
390	            break;
391	        case e_rr_type::CHANZ:
392	            chan_index = 2;
393	            break;
394	        default:
395	            VPR_FATAL_ERROR(VPR_ERROR_ROUTE, "Unsupported channel type.");
396	    }
397	
398	    return chan_index;
399	}
400	
401	} // namespace util
