522	static void compute_router_wire_lookahead(const std::vector<t_segment_inf>& segment_inf_vec,
523	                                          int route_verbosity,
524	                                          bool device_model_warnings) {
525	    vtr::ScopedStartFinishTimer timer("Computing wire lookahead");
526	
527	    const auto& device_ctx = g_vpr_ctx.device();
528	    const auto& grid = device_ctx.grid;
529	
530	    const size_t num_layers = grid.get_num_layers();
531	    // The wire look-ahead table has dimension for channel type.
532	    // In 3-d architectures we have three channel types: CHANX, CHANY, and CHANZ.
533	    // In 2-d architectures we only have two channel types: CHANX and CHANY.
534	    // The size of this dimension is determined based on how many layers are available
535	    // in the architecture.
536	    const size_t chan_type_dim_size = (num_layers == 1) ? 2 : 3;
537	
538	    //Re-allocate
539	    f_wire_cost_map = t_wire_cost_map({num_layers,
540	                                       num_layers,
541	                                       chan_type_dim_size,
542	                                       segment_inf_vec.size(),
543	                                       device_ctx.grid.width(),
544	                                       device_ctx.grid.height()});
545	
546	    int longest_seg_length = 0;
547	    for (const t_segment_inf& seg_inf : segment_inf_vec) {
548	        // longest_seg_length only cares about segments that exist in normal routing wires
549	        // Exclude segment types with 0 frequency e.g. scatter gather segments and unused segments
550	        // these wires can be long, and including them can move us too far from the edge of the die
551	        // and lead to missing data for long distance connections in the lookahead.
552	        if (seg_inf.frequency != 0) {
553	            longest_seg_length = std::max(longest_seg_length, seg_inf.length);
554	        }
555	    }
556	
557	    // Profile each wire segment type
558	    for (size_t from_layer_num = 0; from_layer_num < num_layers; from_layer_num++) {
559	        for (const t_segment_inf& segment_inf : segment_inf_vec) {
560	            std::vector<e_rr_type> chan_types;
561	            if (segment_inf.parallel_axis == e_parallel_axis::X_AXIS) {
562	                chan_types.push_back(e_rr_type::CHANX);
563	            } else if (segment_inf.parallel_axis == e_parallel_axis::Y_AXIS) {
564	                chan_types.push_back(e_rr_type::CHANY);
565	            } else if (segment_inf.parallel_axis == e_parallel_axis::Z_AXIS) {
566	                chan_types.push_back(e_rr_type::CHANZ);
567	            } else {
568	                VTR_ASSERT(segment_inf.parallel_axis == e_parallel_axis::BOTH_AXIS);
569	                // Both for BOTH_AXIS segments and special segments such as clock_networks we want to search in both directions.
570	                chan_types.insert(chan_types.end(), {e_rr_type::CHANX, e_rr_type::CHANY});
571	            }
572	
573	            for (e_rr_type chan_type : chan_types) {
574	                util::t_routing_cost_map routing_cost_map = util::get_routing_cost_map(longest_seg_length,
575	                                                                                       from_layer_num,
576	                                                                                       chan_type,
577	                                                                                       segment_inf,
578	                                                                                       std::unordered_map<int, std::unordered_set<int>>(),
579	                                                                                       /*sample_all_locs=*/true,
580	                                                                                       route_verbosity,
581	                                                                                       device_model_warnings);
582	                if (routing_cost_map.empty()) {
583	                    continue;
584	                }
585	
586	                // boil down the cost list in routing_cost_map at each coordinate to a representative cost entry
587	                // and store it in the lookahead cost map
588	                set_lookahead_map_costs(from_layer_num, segment_inf.seg_index, chan_type, routing_cost_map);
589	
590	                // Fill in missing entries in the lookahead cost map by copying the closest cost entries (cost map was computed based on
591	                // a reference coordinate > (0,0) so some entries that represent a cross-chip distance have not been computed)
592	                fill_in_missing_lookahead_entries(segment_inf.seg_index, chan_type);
593	            }
594	        }
595	    }
596	}

