184	float MapLookahead::get_expected_cost(RRNodeId current_node, RRNodeId target_node, const t_conn_cost_params& params, float R_upstream) const {
185	    const auto& device_ctx = g_vpr_ctx.device();
186	    const auto& rr_graph = device_ctx.rr_graph;
187	
188	    e_rr_type from_rr_type = rr_graph.node_type(current_node);
189	
190	    VTR_ASSERT_SAFE(rr_graph.node_type(target_node) == e_rr_type::SINK);
191	
192	    if (is_flat_) {
193	        return get_expected_cost_flat_router(current_node, target_node, params, R_upstream);
194	    } else {
195	        if (from_rr_type == e_rr_type::CHANX || from_rr_type == e_rr_type::CHANY || from_rr_type == e_rr_type::CHANZ
196	            || from_rr_type == e_rr_type::SOURCE || from_rr_type == e_rr_type::OPIN) {
197	            // Get the total cost using the combined delay and congestion costs
198	            auto [delay_cost, cong_cost] = get_expected_delay_and_cong(current_node, target_node, params, R_upstream);
199	            return delay_cost + cong_cost;
200	        } else if (from_rr_type == e_rr_type::IPIN) { // Change if you're allowing route-throughs
201	            return (device_ctx.rr_indexed_data[RRIndexedDataId(SINK_COST_INDEX)].base_cost);
202	        } else { // Change this if you want to investigate route-throughs
203	            return 0.f;
204	        }
205	    }
206	}
207	
208	float MapLookahead::get_expected_cost_flat_router(RRNodeId current_node, RRNodeId target_node, const t_conn_cost_params& params, float R_upstream) const {
209	    auto& device_ctx = g_vpr_ctx.device();
210	    const auto& rr_graph = device_ctx.rr_graph;
211	
212	    e_rr_type from_rr_type = rr_graph.node_type(current_node);
213	
214	    VTR_ASSERT_SAFE(rr_graph.node_type(target_node) == e_rr_type::SINK);
215	
216	    float delay_cost = 0.;
217	    float cong_cost = 0.;
218	
219	    t_physical_tile_type_ptr from_physical_type = device_ctx.grid.get_physical_type({rr_graph.node_xlow(current_node),
220	                                                                                     rr_graph.node_ylow(current_node),
221	                                                                                     rr_graph.node_layer_low(current_node)});
222	    int from_node_ptc_num = rr_graph.node_ptc_num(current_node);
223	    t_physical_tile_type_ptr to_physical_type = device_ctx.grid.get_physical_type({rr_graph.node_xlow(target_node),
224	                                                                                   rr_graph.node_ylow(target_node),
225	                                                                                   rr_graph.node_layer_low(target_node)});
226	    float delay_offset_cost = 0.;
227	    float cong_offset_cost = 0.;
228	    int to_node_ptc_num = rr_graph.node_ptc_num(target_node);
229	    int to_layer_num = rr_graph.node_layer_low(target_node);
230	    // We have not checked the multi-layer FPGA for flat routing
231	    VTR_ASSERT(rr_graph.node_layer_low(current_node) == rr_graph.node_layer_low(target_node));
232	    if (from_rr_type == e_rr_type::CHANX || from_rr_type == e_rr_type::CHANY) {
233	        std::tie(delay_cost, cong_cost) = get_expected_delay_and_cong(current_node, target_node, params, R_upstream);
234	
235	        // delay_cost and cong_cost only represent the cost to get to the root-level pins. The below offsets are used to represent the intra-cluster cost
236	        // of getting to a sink
237	        delay_offset_cost = params.criticality * tile_min_cost.at(to_physical_type->index).at(to_node_ptc_num).delay;
238	        cong_offset_cost = (1. - params.criticality) * tile_min_cost.at(to_physical_type->index).at(to_node_ptc_num).congestion;
239	
240	        return delay_cost + cong_cost + delay_offset_cost + cong_offset_cost;
241	    } else if (from_rr_type == e_rr_type::OPIN) {
242	        if (is_inter_cluster_node(rr_graph, current_node)) {
243	            // Similar to CHANX and CHANY
244	            std::tie(delay_cost, cong_cost) = get_expected_delay_and_cong(current_node, target_node, params, R_upstream);
245	
246	            delay_offset_cost = params.criticality * tile_min_cost.at(to_physical_type->index).at(to_node_ptc_num).delay;
247	            cong_offset_cost = (1. - params.criticality) * tile_min_cost.at(to_physical_type->index).at(to_node_ptc_num).congestion;
248	            return delay_cost + cong_cost + delay_offset_cost + cong_offset_cost;
249	        } else {
250	            if (node_in_same_physical_tile(current_node, target_node)) {
251	                delay_offset_cost = 0.;
252	                cong_offset_cost = 0.;
253	                const auto& pin_delays = intra_tile_pin_primitive_pin_delay.at(from_physical_type->index)[from_node_ptc_num];
254	                auto pin_delay_itr = pin_delays.find(rr_graph.node_ptc_num(target_node));
255	                if (pin_delay_itr == pin_delays.end()) {
256	                    // There isn't any intra-cluster path to connect the current OPIN to the SINK, thus it has to outside.
257	                    // The best estimation we have now, it the minimum intra-cluster delay to the sink. However, this cost is incomplete,
258	                    // since it does not consider the cost of going outside of the cluster and, then, returning to it.
259	                    delay_cost = params.criticality * tile_min_cost.at(to_physical_type->index).at(to_node_ptc_num).delay;
260	                    cong_cost = (1. - params.criticality) * tile_min_cost.at(to_physical_type->index).at(to_node_ptc_num).congestion;
261	                    return delay_cost + cong_cost;
262	                } else {
263	                    delay_cost = params.criticality * pin_delay_itr->second.delay;
264	                    cong_cost = (1. - params.criticality) * pin_delay_itr->second.congestion;
265	                }
266	            } else {
